Parfait. Voici bootstrap.py — un seul fichier qui :


installe les catalogues minimaux (template dynamique + pages/modules/forms + providers IA + types de BDD),


met en place un système de hooks (base → alias) où hook_after_config_install est un alias de hook_after,


exécute le scénario d’installation (et rend la page d’install),


lance deux serveurs : statique (port 8081) et API (port 8082),


gère /api/install (persist JSON local), /api/login,


écrit des logs (logs/bootstrap.log) et un report append-only (reports/install_report.jsonl),


rend public/index.html via le template dynamique <!DOCTYPE html><html lang="{lang}">{head}{body}</html>.


Copie ce fichier tel quel et lance-le.
pythonCopier le code#!/usr/bin/env python3
# description : Single-file bootstrap - installe les catalogues minimaux (template dynamique + install wizard),
#               mini-framework de hooks (base -> alias), execute le scenario d'installation et lance un serveur local.
# howto :
#   python3 bootstrap.py
#   - Ouvre http://localhost:8081 pour l'installation (type WordPress).
# Notes :
#   - Un seul fichier a l'installation. Tout le reste (catalogs/HTML/logs) est genere au runtime.
#   - Hooks : les hooks specifiques (ex: hook_after_config_install) sont des alias des hooks de base (hook_after).
#             Quand un hook de base est declenche, il execute les actions associees a ses alias enregistres.

import os, json
from pathlib import Path
from http.server import HTTPServer, SimpleHTTPRequestHandler, BaseHTTPRequestHandler
from datetime import datetime
from threading import Thread
import time

PORT = int(os.environ.get("BOOTSTRAP_PORT", "8081"))  # static on PORT, api on PORT+1

# -----------------------------
# Utils (logs & fs)
# -----------------------------
def now_iso():
    return datetime.utcnow().replace(microsecond=0).isoformat() + "Z"

def ensure_dirs(root):
    for p in ["catalogs/templates", "catalogs/ui", "catalogs/data", "public", "logs", "reports", "config"]:
        (root / p).mkdir(parents=True, exist_ok=True)

def write_json(path: Path, obj):
    path.parent.mkdir(parents=True, exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        json.dump(obj, f, indent=2, ensure_ascii=False)

def append_log(root, line):
    with open(root / "logs/bootstrap.log", "a", encoding="utf-8") as f:
        f.write(line.rstrip() + "\n")

def append_report(root, ident, payload):
    entry = {"timestamp": now_iso(), "ident": ident, **payload}
    with open(root / "reports/install_report.jsonl", "a", encoding="utf-8") as f:
        f.write(json.dumps(entry, ensure_ascii=False) + "\n")

# -----------------------------
# Catalogs (minima) — IVC×DRO
# -----------------------------
def install_min_catalogs(root: Path):
    # dynamic template pieces
    write_json(root / "catalogs/templates/lang.json",
               {"identity":{"ident":"lang","name":"Langue"},
                "definitions":{"value":"en"}})
    write_json(root / "catalogs/templates/head.json",
               {"identity":{"ident":"head","name":"Head"},
                "definitions":{"value":"<head><meta charset='UTF-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>LaNostrAI - Setup</title></head>"}})
    write_json(root / "catalogs/templates/body.json",
               {"identity":{"ident":"body","name":"Body"},
                "definitions":{"value":"<body><!-- placeholder:dynamic_content --></body>"}})
    write_json(root / "catalogs/templates/dynamic_template.json",
               {"identity":{"ident":"dynamic_template","name":"Template HTML dynamique"},
                "definitions":{"value":"<!DOCTYPE html><html lang=\"{lang}\">{head}{body}</html>"},
                "context":{"relations":{"consumes":["lang","head","body"]}}})

    # data catalogs (providers/models, db types)
    write_json(root / "catalogs/data/ai_providers.json",
               {"providers":[
                   {"ident":"openai","label":"OpenAI","models":["gpt-4o-mini","gpt-4.1","o4-mini"]},
                   {"ident":"anthropic","label":"Anthropic","models":["claude-3.5-sonnet","claude-3-haiku"]},
                   {"ident":"google","label":"Google","models":["gemini-1.5-flash","gemini-1.5-pro"]},
                   {"ident":"mistral","label":"Mistral","models":["mistral-large","mistral-small"]}
               ]})
    write_json(root / "catalogs/data/db_types.json",
               {"types":[
                   {"ident":"json","label":"JSON (fichier)",
                    "params_schema":[{"name":"file_path","type":"text","placeholder":"config/data.json"}]},
                   {"ident":"sqlite","label":"SQLite",
                    "params_schema":[{"name":"file_path","type":"text","placeholder":"config/data.sqlite"}]},
                   {"ident":"mongodb","label":"MongoDB",
                    "params_schema":[{"name":"host","type":"text"},{"name":"port","type":"number"},
                                     {"name":"user","type":"text"},{"name":"password","type":"password"},{"name":"db","type":"text"}]},
                   {"ident":"postgres","label":"PostgreSQL",
                    "params_schema":[{"name":"host","type":"text"},{"name":"port","type":"number"},
                                     {"name":"user","type":"text"},{"name":"password","type":"password"},{"name":"db","type":"text"}]}
               ]})

    # pages/modules/forms
    write_json(root / "catalogs/ui/page_install.json",
               {"identity":{"ident":"page_install","name":"Page d'installation"},
                "context":{"relations":{"loads":["module_config"]}}})
    write_json(root / "catalogs/ui/page_home.json",
               {"identity":{"ident":"page_home","name":"Page d'accueil"},
                "context":{"relations":{"loads":["module_login"]}}})
    write_json(root / "catalogs/ui/module_config.json",
               {"identity":{"ident":"module_config","name":"Module de configuration"},
                "definitions":{"value":"FORM_INSTALL"},
                "context":{"relations":{"contains":["form_install"]}}})
    write_json(root / "catalogs/ui/module_login.json",
               {"identity":{"ident":"module_login","name":"Module de login"},
                "definitions":{"value":"FORM_LOGIN"},
                "context":{"relations":{"contains":["form_login"]}}})

    write_json(root / "catalogs/ui/form_install.json",
               {"identity":{"ident":"form_install","name":"Formulaire d'installation"},
                "context":{"relations":{"elements":["section_admin","section_ai","section_db","btn_submit_install"]}}})
    write_json(root / "catalogs/ui/form_login.json",
               {"identity":{"ident":"form_login","name":"Formulaire de login"},
                "context":{"relations":{"elements":["input_login","input_password","btn_submit_login"]}}})

    # admin section + fields
    write_json(root / "catalogs/ui/section_admin.json",
               {"identity":{"ident":"section_admin","name":"Section Admin"},
                "context":{"relations":{"elements":["input_admin_email","input_admin_login","input_admin_password"]}}})
    write_json(root / "catalogs/ui/input_admin_email.json",
               {"identity":{"ident":"input_admin_email","name":"Email admin"},
                "definitions":{"type":"email","placeholder":"you@example.com","required":True}})
    write_json(root / "catalogs/ui/input_admin_login.json",
               {"identity":{"ident":"input_admin_login","name":"Login admin"},
                "definitions":{"type":"text","placeholder":"admin","required":True}})
    write_json(root / "catalogs/ui/input_admin_password.json",
               {"identity":{"ident":"input_admin_password","name":"Mot de passe admin"},
                "definitions":{"type":"password","placeholder":"********","required":True}})

    # AI & DB sections (repeaters)
    write_json(root / "catalogs/ui/section_ai.json",
               {"identity":{"ident":"section_ai","name":"Section IA"},
                "definitions":{"repeater":True,"group":["select_ai_provider","select_ai_models","input_ai_key","btn_add_ai_provider"]}})
    write_json(root / "catalogs/ui/section_db.json",
               {"identity":{"ident":"section_db","name":"Section BDD"},
                "definitions":{"repeater":True,"group":["select_db_type","fieldset_db_params","radio_default_db","btn_add_db_option"]}})

    # login form generic
    write_json(root / "catalogs/ui/input_login.json",
               {"identity":{"ident":"input_login","name":"Login"},
                "definitions":{"type":"text","placeholder":"admin","required":True}})
    write_json(root / "catalogs/ui/input_password.json",
               {"identity":{"ident":"input_password","name":"Mot de passe"},
                "definitions":{"type":"password","placeholder":"********","required":True}})
    write_json(root / "catalogs/ui/btn_submit_login.json",
               {"identity":{"ident":"btn_submit_login","name":"Bouton login"},
                "definitions":{"type":"button","action":"submit_login","label":"Se connecter"}})
    write_json(root / "catalogs/ui/btn_submit_install.json",
               {"identity":{"ident":"btn_submit_install","name":"Bouton installer"},
                "definitions":{"type":"button","action":"submit_install","label":"Installer"}})

# -----------------------------
# Hooks Framework (base -> alias)
# -----------------------------
HOOK_REGISTRY = {"hook_before": [], "hook_after": [], "hook_onfailure": []}

def register_hook_alias(base_hook: str, alias_ident: str, actions):
    HOOK_REGISTRY.setdefault(base_hook, []).append({"alias": alias_ident, "actions": actions})

def call_hook(root: Path, base_hook: str, context: dict):
    append_log(root, f"[hook] {base_hook} entered (aliases={len(HOOK_REGISTRY.get(base_hook, []))})")
    for entry in HOOK_REGISTRY.get(base_hook, []):
        alias = entry["alias"]
        for action in entry.get("actions", []):
            try:
                append_log(root, f"[hook] run {alias} -> {action}")
                if action == "render_install_page":
                    render_install_page(root)
                elif action == "persist_install_snapshot":
                    persist_install_snapshot(root, context)
                elif action == "switch_to_home":
                    render_home_login(root)
                else:
                    append_log(root, f"[hook] unknown action: {action}")
            except Exception as e:
                append_log(root, f"[hook][error] {alias}:{action} failed: {e}")
    append_log(root, f"[hook] {base_hook} exited")

def persist_install_snapshot(root: Path, context: dict):
    write_json(root / "config/install_snapshot.json", {"status": "in_progress", "ctx": context, "created_at": now_iso()})
    append_report(root, "install_snapshot", {"status": "in_progress"})

# -----------------------------
# Rendering
# -----------------------------
def render_from_dynamic_template(root: Path, body_html: str):
    with open(root / "catalogs/templates/lang.json","r",encoding="utf-8") as f:
        lang = json.load(f)["definitions"]["value"]
    with open(root / "catalogs/templates/head.json","r",encoding="utf-8") as f:
        head = json.load(f)["definitions"]["value"]
    html = "<!DOCTYPE html><html lang='"+lang+"'>"+head+"<body>"+body_html+"</body></html>"
    (root / "public").mkdir(exist_ok=True)
    with open(root / "public/index.html","w",encoding="utf-8") as f:
        f.write(html)
    append_log(root, "[render] public/index.html updated")

def render_install_page(root: Path):
    body_html = """
<div id='app' style='max-width:900px;margin:40px auto;font-family:system-ui, -apple-system, Segoe UI, Roboto;'>
  <h1>Installation - LaNostrAI</h1>
  <p>Configure l'admin, l'IA et la base de donnees. Tu peux ajouter plusieurs providers IA et plusieurs BDD (une seule par defaut).</p>

  <h2>Admin</h2>
  <label>Email<br><input id='admin_email' type='email' placeholder='you@example.com' required></label><br><br>
  <label>Login<br><input id='admin_login' type='text' placeholder='admin' required></label><br><br>
  <label>Mot de passe<br><input id='admin_password' type='password' placeholder='********' required></label>

  <h2>IA (providers + modeles + cles)</h2>
  <div id='ai_zone'></div>
  <button id='add_ai'>+ Ajouter un provider IA</button>

  <h2>Base de donnees</h2>
  <div id='db_zone'></div>
  <button id='add_db'>+ Ajouter une base</button>
  <p style='font-size:12px;color:#555'>Une seule base peut etre <em>par defaut</em> pour l'authentification.</p>

  <hr style='margin:24px 0'>
  <button id='submit_install' style='padding:10px 16px;'>Installer</button>

  <p id='msg' style='color:green;'></p>
</div>

<script>
async function loadJSON(path){ const r = await fetch(path); return await r.json(); }
let providers = []; let dbTypes = [];

function makeAIBlock(idx){
  const c = document.createElement('div'); c.style.border='1px solid #ddd'; c.style.padding='12px'; c.style.margin='12px 0'; c.dataset.index=idx;
  const selProv = document.createElement('select'); selProv.innerHTML = '<option value=\"\">-- provider --</option>';
  providers.forEach(p => { const o=document.createElement('option'); o.value=p.ident; o.text=p.label; selProv.append(o); });
  const selModels = document.createElement('select'); selModels.multiple=true; selModels.size=3; selModels.style.marginLeft='8px';
  selProv.addEventListener('change', ()=>{ const obj = providers.find(p=>p.ident===selProv.value)||{models:[]}; selModels.innerHTML=''; obj.models.forEach(m=>{ const o=document.createElement('option'); o.value=m; o.text=m; selModels.append(o); }); });
  const key = document.createElement('input'); key.type='text'; key.placeholder='API key'; key.style.marginLeft='8px'; key.size=30;
  c.append('Provider: ', selProv, ' Modeles: ', selModels, ' Cle: ', key); return c;
}

function makeDBBlock(idx){
  const c = document.createElement('div'); c.style.border='1px solid #ddd'; c.style.padding='12px'; c.style.margin='12px 0'; c.dataset.index=idx;
  const selType = document.createElement('select'); selType.innerHTML = '<option value=\"\">-- type de base --</option>';
  dbTypes.forEach(t => { const o=document.createElement('option'); o.value=t.ident; o.text=t.label; selType.append(o); });
  const paramsZone = document.createElement('span'); paramsZone.style.marginLeft='8px';
  const radioDef = document.createElement('input'); radioDef.type='radio'; radioDef.name='default_db'; radioDef.title='Definir comme par defaut'; radioDef.style.marginLeft='8px';
  selType.addEventListener('change', ()=>{ const t = dbTypes.find(x=>x.ident===selType.value); paramsZone.innerHTML=''; if(t){ (t.params_schema||[]).forEach(field=>{ const inp=document.createElement('input'); inp.type=(field.type==='number'?'number':(field.type==='password'?'password':'text')); inp.placeholder=field.placeholder||field.name; inp.dataset.name=field.name; inp.style.marginLeft='6px'; paramsZone.append(inp); }); } });
  c.append('Type: ', selType, paramsZone, '  Par defaut: ', radioDef); return c;
}

async function init(){
  providers = (await loadJSON('/catalogs/data/ai_providers.json')).providers;
  dbTypes = (await loadJSON('/catalogs/data/db_types.json')).types;
  const aiZone = document.getElementById('ai_zone'); const dbZone = document.getElementById('db_zone');
  let aiCount=0, dbCount=0;
  document.getElementById('add_ai').onclick = ()=> aiZone.appendChild(makeAIBlock(aiCount++));
  document.getElementById('add_db').onclick = ()=> dbZone.appendChild(makeDBBlock(dbCount++));
  document.getElementById('add_ai').click(); document.getElementById('add_db').click();
  document.getElementById('submit_install').onclick = async ()=>{
    const admin = { email: document.getElementById('admin_email').value.trim(), login: document.getElementById('admin_login').value.trim(), password: document.getElementById('admin_password').value };
    const ai = []; aiZone.querySelectorAll('div[data-index]').forEach(div=>{
      const selects=div.getElementsByTagName('select'); const provider=selects[0].value; const modelsSel=selects[1];
      const models=Array.from(modelsSel.options).filter(o=>o.selected).map(o=>o.value);
      const key=div.querySelector('input[type=\"text\"]').value.trim();
      if(provider && key) ai.push({provider, models, key, active:true});
    });
    let defaultCount=0; const db=[]; dbZone.querySelectorAll('div[data-index]').forEach(div=>{
      const type=div.getElementsByTagName('select')[0].value;
      const params={}; div.querySelectorAll('span input').forEach(inp=>{ params[inp.dataset.name]=inp.value; });
      const isDef=div.querySelector('input[type=\"radio\"]').checked; if(isDef) defaultCount += 1;
      db.push({type, params, is_default:isDef, active:true});
    });
    if(!admin.login || !admin.password){ alert('Login & mot de passe admin requis'); return; }
    if(defaultCount !== 1){ alert('Une seule base doit etre par defaut'); return; }
    const r = await fetch('/api/install', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({admin, ai, db}) });
    const j = await r.json(); const msg = document.getElementById('msg'); msg.textContent = j.message || 'OK';
    if(j.status==='completed') setTimeout(()=>location.reload(), 600);
  };
}
init();
</script>
"""
    render_from_dynamic_template(root, body_html)

def render_home_login(root: Path):
    body_html = """
<div style='max-width:520px;margin:40px auto;font-family:system-ui'>
  <h1>Bienvenue</h1>
  <p>Connectez-vous avec l'identifiant configure.</p>
  <form onsubmit='event.preventDefault(); login();'>
    <label>Login<br><input id='login' type='text' required></label><br><br>
    <label>Mot de passe<br><input id='pwd' type='password' required></label><br><br>
    <button type='submit'>Se connecter</button>
  </form>
  <p id='msg' style='color:crimson'></p>
</div>
<script>
async function login(){
  const payload = { login: document.getElementById('login').value, password: document.getElementById('pwd').value };
  const r = await fetch('/api/login', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify(payload) });
  const j = await r.json(); const msg = document.getElementById('msg');
  if(j.status==='ok'){ msg.style.color='green'; msg.textContent='Connecte !'; } else { msg.textContent = j.message || 'Echec'; }
}
</script>
"""
    render_from_dynamic_template(root, body_html)

# -----------------------------
# Scenario: install_wizard (GET/EXECUTE/VALIDATE/RENDER)
# -----------------------------
def scenario_install_wizard(root: Path):
    ctx = {"phase": "install"}
    append_log(root, "[scenario] install_wizard::GET")
    write_json(root / "config/install_snapshot.json", {"status": "in_progress", "created_at": now_iso()})
    append_report(root, "install_snapshot", {"status": "in_progress"})
    append_log(root, "[scenario] install_wizard::EXECUTE")
    append_log(root, "[scenario] install_wizard::VALIDATE")
    append_log(root, "[scenario] install_wizard::RENDER")
    call_hook(root, "hook_after", ctx)

# -----------------------------
# Hook aliases registration
# -----------------------------
def register_install_hooks():
    # hook_after_config_install est un alias de hook_after (centre de controle)
    register_hook_alias("hook_after", "hook_after_config_install", actions=["render_install_page"])

# -----------------------------
# HTTP servers (static + api)
# -----------------------------
class BootstrapHandler(SimpleHTTPRequestHandler):
    def do_GET(self):
        if self.path == "/health":
            self.send_response(200); self.send_header("Content-Type","application/json"); self.end_headers()
            self.wfile.write(json.dumps({"status":"ok","ts":now_iso()}).encode("utf-8")); return
        return super().do_GET()

class ApiHandler(BaseHTTPRequestHandler):
    def _read_json(self):
        ln = int(self.headers.get("Content-Length", 0))
        data = self.rfile.read(ln) if ln else b"{}"
        try: return json.loads(data.decode("utf-8"))
        except: return {}
    def _send(self, code, obj):
        self.send_response(code); self.send_header("Content-Type","application/json"); self.end_headers()
        self.wfile.write(json.dumps(obj, ensure_ascii=False).encode("utf-8"))
    def do_POST(self):
        root = Path(__file__).parent.resolve()
        if self.path == "/api/install":
            payload = self._read_json()
            admin_ok = bool(payload.get("admin", {}).get("login") and payload.get("admin", {}).get("password"))
            dbs = payload.get("db", []) or []
            default_count = sum(1 for d in dbs if d.get("is_default"))
            if not admin_ok: return self._send(400, {"status":"error","message":"Admin login & password requis"})
            if default_count != 1: return self._send(400, {"status":"error","message":"Une seule base doit etre par defaut"})
            # persist temp config
            write_json(root / "config/system_config.json", payload)
            write_json(root / "config/admin_account.json", payload.get("admin"))
            append_report(root, "install_completed", {"status": "completed"})
            append_log(root, "[install] configuration persisted (system_config.json)")
            # switch to home/login
            render_home_login(root)
            return self._send(200, {"status":"completed","message":"Installation terminee. Redirection..."})
        if self.path == "/api/login":
            payload = self._read_json()
            try:
                with open(root / "config/admin_account.json","r",encoding="utf-8") as f:
                    admin = json.load(f)
            except FileNotFoundError:
                return self._send(400, {"status":"error","message":"Aucun compte admin configure"})
            ok = (payload.get("login")==admin.get("login")) and (payload.get("password")==admin.get("password"))
            return self._send(200, {"status":"ok"} if ok else {"status":"error","message":"Identifiants invalides"})
        return self._send(404, {"status":"error","message":"Not found"})

def start_server(root: Path):
    os.chdir(root)  # serve /public and /catalogs
    httpd_static = HTTPServer(("", PORT), BootstrapHandler)
    def run_static():
        print(f"[server] static on http://localhost:{PORT}")
        append_log(root, f"[server] static on {PORT}")
        httpd_static.serve_forever()
    httpd_api = HTTPServer(("", PORT+1), ApiHandler)
    def run_api():
        print(f"[server] api on http://localhost:{PORT+1}")
        append_log(root, f"[server] api on {PORT+1}")
        httpd_api.serve_forever()
    Thread(target=run_static, daemon=True).start()
    Thread(target=run_api, daemon=True).start()
    while True:
        time.sleep(1)

# -----------------------------
# Main
# -----------------------------
def main():
    root = Path(__file__).parent.resolve()
    ensure_dirs(root); append_log(root, "[bootstrap] start")
    install_min_catalogs(root); append_log(root, "[bootstrap] catalogs installed")
    register_install_hooks(); append_log(root, "[bootstrap] hooks registered")
    scenario_install_wizard(root); append_log(root, "[bootstrap] scenario_install_wizard executed")
    start_server(root)

if __name__ == "__main__":
    main()

