        if self.path == "/api/login":
            payload = self._read_json()
            try:
                admin = json.loads((root / "config" / "admin_account.json").read_text(encoding="utf-8"))
            except FileNotFoundError:
                return self._send_json(400, {"status":"error","message":"Aucun compte admin configure"})
            ok = (payload.get("login")==admin.get("login")) and (payload.get("password")==admin.get("password"))
            return self._send_json(200, {"status":"ok"} if ok else {"status":"error","message":"Identifiants invalides"})

        self._send_json(404, {"status":"error","message":"Not found"})

def start_server_same_port(root: Path, port: int):
    httpd = HTTPServer(("", port), AppHandler)
    print(f"[server] http on http://localhost:{port}")
    append_log(root, f"[server] http on {port}")
    httpd.serve_forever()

