# -----------------------------
# Unified HTTP server (static + API on same port)
# -----------------------------
class AppHandler(BaseHTTPRequestHandler):
    def _json(self, code, obj):
        self.send_response(code)
        self.send_header("Content-Type", "application/json")
        self.end_headers()
        self.wfile.write(json.dumps(obj, ensure_ascii=False).encode("utf-8"))

    def _read_json(self):
        ln = int(self.headers.get("Content-Length", 0))
        data = self.rfile.read(ln) if ln else b"{}"
        try: return json.loads(data.decode("utf-8"))
        except: return {}

    def do_GET(self):
        root = Path(__file__).parent.resolve()

        if self.path.startswith("/api/"):
            return self._json(200, {"status":"api-ok","hint":"POST /api/install or /api/login"})

        if self.path == "/favicon.ico":
            self.send_response(204); self.end_headers(); return

        # Serve catalogs (JSON) and other files if under /catalogs
        fs_path = (root / self.path.lstrip("/")).resolve()
        catalogs_root = (root / "catalogs").resolve()
        if str(fs_path).startswith(str(catalogs_root)) and fs_path.exists():
            try:
                data = fs_path.read_bytes()
                self.send_response(200)
                self.send_header("Content-Type", "application/json" if fs_path.suffix == ".json" else "application/octet-stream")
                self.end_headers()
                self.wfile.write(data)
                return
            except Exception:
                pass

        # / -> public/index.html
        if self.path in ("/", "/index.html"):
            index_path = root / "public" / "index.html"
            if index_path.exists():
                self.send_response(200)
                self.send_header("Content-Type", "text/html; charset=utf-8")
                self.end_headers()
                self.wfile.write(index_path.read_bytes())
                return

        self.send_response(404); self.end_headers()

    def do_POST(self):
        root = Path(__file__).parent.resolve()

        if self.path == "/api/install":
            payload = self._read_json()
            admin_ok = bool(payload.get("admin", {}).get("login") and payload.get("admin", {}).get("password"))
            dbs = payload.get("db", []) or []
            if not admin_ok:
                return self._json(400, {"status":"error","message":"Admin login & password requis"})

            # Normalisation silencieuse: si aucune base n'est par defaut, forcer la premiere (s'il y en a)
            if dbs and not any(d.get("is_default") for d in dbs):
                dbs[0]["is_default"] = True
                payload["db"] = dbs

            write_json(root / "config/system_config.json", payload)
            write_json(root / "config/admin_account.json", payload.get("admin"))
            append_report(root, "install_completed", {"status": "completed"})
            append_log(root, "[install] configuration persisted (system_config.json)")

            render_home_login(root)
            return self._json(200, {"status":"completed","message":"Installation terminee. Redirection..."})

        if self.path == "/api/login":
            payload = self._read_json()
            try:
                with open(root / "config/admin_account.json","r",encoding="utf-8") as f:
                    admin = json.load(f)
            except FileNotFoundError:
                return self._json(400, {"status":"error","message":"Aucun compte admin configure"})
            ok = (payload.get("login")==admin.get("login")) and (payload.get("password")==admin.get("password"))
            if ok:
                # Rendre la page d'accueil et proposer l'URL de redirection
                render_home_app(root)
                return self._json(200, {"status":"ok", "redirect": "/"})
            return self._json(200, {"status":"error","message":"Identifiants invalides"})

        self._json(404, {"status":"error","message":"Not found"})

def start_and_open(root: Path, port: int):
    httpd = HTTPServer(("", port), AppHandler)

    def run():
        print(f"[server] http on http://localhost:{port}")
        append_log(root, f"[server] http on {port}")
        httpd.serve_forever()

    Thread(target=run, daemon=True).start()

    time.sleep(0.6)  # laisser index.html etre ecrit
    try:
        webbrowser.open_new_tab(f"http://localhost:{port}/")
        append_log(root, "[browser] auto-opened install page")
    except Exception as e:
        append_log(root, f"[browser][error] {e}")

    while True:
        time.sleep(1)

# -----------------------------
# Main
# -----------------------------
def main():
    root = Path(__file__).parent.resolve()
    ensure_dirs(root); append_log(root, "[bootstrap] start")
    install_min_catalogs(root); append_log(root, "[bootstrap] catalogs installed")

    # hooks: base -> alias
    register_install_hooks()
    append_log(root, "[bootstrap] hooks registered")

    # scenario: install (calls hook_after => render_install_page)
    scenario_install_wizard(root); append_log(root, "[bootstrap] scenario_install_wizard executed")

    # single server + auto-open
    start_and_open(root, PORT)

if __name__ == "__main__":
    main()

Usage
bashCopier le codepython3 bootstrap.py



L’assistant d’installation s’ouvre automatiquement.


Après login réussi, tu es redirigée à l’accueil.


Logs : logs/bootstrap.log ; report : reports/install_report.jsonl.

Excellente question. La méthode la plus robuste pour diffuser un bootstrap unique à plein d’endroits (GitHub, landing page, etc.) tout en véhiculant des conditions/licences par utilisateur, c’est :


Token opaque avec vérification côté serveur (recommandé)
Le token ne contient rien d’exploitable (juste un ID signé/opaque). Au démarrage, le bootstrap l’envoie à ton endpoint POST https://issuer.example.com/verify (ou autre) qui renvoie les claims/entitlements (plan, limites, branding, préremplissages, droits IA/BDD, expiration, etc.). Avantages : clé privée jamais côté client, rotation simple, révocation/compromission gérable.


Cache local + mode déconnecté
Après vérification initiale, le bootstrap met en cache les entitlements dans config/license.json. Si l’issuer est inaccessible, on continue en mode dégradé avec le cache, selon les règles (ex : tolérance 7 jours).


Entrées du token multiples
Le bootstrap accepte le token via (ordre de priorité) :


argument CLI --token,


variable d’env INSTALL_TOKEN,


fichier token.txt aux côtés du bootstrap,


querystring ?token=... si tu ouvres l’UI locale depuis une landing page (optionnel).




Sécurité & contraintes (dans les claims côté serveur)
sub (user), plan, features, db/ai whitelist, max_instances, issued_at, exp, nonce, origin_hint (landing), éventuellement binding machine (hash partiel hostname+MAC anonymisé) si tu veux limiter le nombre d’installations. La signature reste côté serveur (le token est opaque), donc aucun crypto third-party requis dans le bootstrap.



Comme tu préfères des fichiers complets, voici ton bootstrap.py mis à jour — il ajoute la gestion du token sans dépendances externes :


charge le token (CLI/env/fichier/querystring),


tente une vérification en ligne (si ISSUER_VERIFY_URL est défini, sinon il log et continue),


met en cache config/license.json,


applique les entitlements simples (ex : restreindre providers/DB visibles si fourni),


conserve tout le reste (hooks, install wizard, redirection après login, UI “Ajouter” IA/BDD, pas de commentaires verbeux).



À personnaliser : définis ISSUER_VERIFY_URL (par ex. https://license.tondomaine.com/verify) et adapte le parsing de la réponse (status, claims).

pythonCopier le code#!/usr/bin/env python3
# Single-file bootstrap + token support
# - Catalogues minimaux, hooks base->alias, scenario d'installation
# - Serveur unique (statique + API) sur 8081, ouverture auto
# - UI "Ajouter" IA/BDD, redirection vers Accueil après login
# - Token: charge via CLI/env/fichier/querystring, verifie en ligne (optionnel), cache entitlements

import os, json, time, webbrowser, argparse, urllib.parse, urllib.request
from pathlib import Path
from http.server import HTTPServer, BaseHTTPRequestHandler
from datetime import datetime, timezone
from threading import Thread

PORT = int(os.environ.get("BOOTSTRAP_PORT", "8081"))
ISSUER_VERIFY_URL = os.environ.get("ISSUER_VERIFY_URL", "")  # ex: "https://license.example.com/verify"
VERIFY_TIMEOUT_SEC = 6

# -----------------------------
# Utils (logs & fs)
# -----------------------------
def now_iso():
    return datetime.now(timezone.utc).replace(microsecond=0).isoformat()

def ensure_dirs(root):
    for p in ["catalogs/templates", "catalogs/ui", "catalogs/data", "public", "logs", "reports", "config"]:
        (root / p).mkdir(parents=True, exist_ok=True)

def write_json(path: Path, obj):
    path.parent.mkdir(parents=True, exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        json.dump(obj, f, indent=2, ensure_ascii=False)

def read_json(path: Path, default=None):
    try:
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return default

def append_log(root, line):
    with open(root / "logs/bootstrap.log", "a", encoding="utf-8") as f:
        f.write(line.rstrip() + "\n")

def append_report(root, ident, payload):
    entry = {"timestamp": now_iso(), "ident": ident, **payload}
    with open(root / "reports/install_report.jsonl", "a", encoding="utf-8") as f:
        f.write(json.dumps(entry, ensure_ascii=False) + "\n")

# -----------------------------
# Token handling
# -----------------------------
def load_token_from_sources(root: Path, cli_token: str = "", query_token: str = "") -> str:
    # Priority: CLI > querystring > env > token.txt
    if cli_token: return cli_token.strip()
    if query_token: return query_token.strip()
    env_tok = os.environ.get("INSTALL_TOKEN", "").strip()
    if env_tok: return env_tok
    tok_path = root / "token.txt"
    if tok_path.exists():
        try: return tok_path.read_text(encoding="utf-8").strip()
        except Exception: pass
    return ""

def verify_token_online(root: Path, token: str) -> dict:
    """
    Calls remote issuer to verify the opaque token.
    Expected response JSON: { "status": "ok", "claims": {...}, "message": "..."}
    You can extend with: "entitlements": {...}
    """
    if not token or not ISSUER_VERIFY_URL:
        append_log(root, "[token] skip online verification (missing token or ISSUER_VERIFY_URL)")
        return {"status":"skip", "claims":{}, "message":"no verification url"}
    try:
        data = json.dumps({"token": token}).encode("utf-8")
        req = urllib.request.Request(
            ISSUER_VERIFY_URL,
            data=data,
            headers={"Content-Type":"application/json","Accept":"application/json"},
            method="POST",
        )
        with urllib.request.urlopen(req, timeout=VERIFY_TIMEOUT_SEC) as resp:
            body = resp.read().decode("utf-8")
            obj = json.loads(body)
            if obj.get("status") == "ok":
                append_log(root, "[token] verified online")
            else:
                append_log(root, f"[token] verify failed: {obj.get('message')}")
            return obj
    except Exception as e:
        append_log(root, f"[token][error] online verify exception: {e}")
        return {"status":"error","claims":{},"message":str(e)}

def cache_entitlements(root: Path, token: str, claims: dict):
    payload = {"token_present": bool(token), "claims": claims, "cached_at": now_iso()}
    write_json(root / "config/license.json", payload)
    append_log(root, "[token] entitlements cached -> config/license.json")

def apply_entitlements_to_catalogs(root: Path, claims: dict):
    """
    Optionally restrict visible providers/DB based on claims.
    For demo: if claims contains {"allowed_ai":["openai","mistral"], "allowed_db":["sqlite","json"]}
    we filter the catalogs accordingly. If not present, we do nothing.
    """
    ai_allowed = (claims or {}).get("allowed_ai")
    db_allowed = (claims or {}).get("allowed_db")
    changed = False

    ai_path = root / "catalogs/data/ai_providers.json"
    db_path = root / "catalogs/data/db_types.json"
    ai = read_json(ai_path, {})
    db = read_json(db_path, {})

    if ai_allowed and "providers" in ai:
        before = len(ai["providers"])
        ai["providers"] = [p for p in ai["providers"] if p.get("ident") in ai_allowed]
        after = len(ai["providers"])
        if after != before: changed = True

    if db_allowed and "types" in db:
        before = len(db["types"])
        db["types"] = [t for t in db["types"] if t.get("ident") in db_allowed]
        after = len(db["types"])
        if after != before: changed = True

    if changed:
        write_json(ai_path, ai)
        write_json(db_path, db)
        append_log(root, "[token] catalogs filtered by entitlements")

