def register_install_hooks():
    register_hook_alias("hook_after", "hook_after_config_install", actions=["render_install_page"])

# -----------------------------
# Unified HTTP server
# -----------------------------
class AppHandler(BaseHTTPRequestHandler):
    def _json(self, code, obj):
        self.send_response(code); self.send_header("Content-Type", "application/json"); self.end_headers()
        self.wfile.write(json.dumps(obj, ensure_ascii=False).encode("utf-8"))

    def _read_json(self):
        ln = int(self.headers.get("Content-Length", 0))
        data = self.rfile.read(ln) if ln else b"{}"
        try: return json.loads(data.decode("utf-8"))
        except: return {}

    def do_GET(self):
        root = Path(__file__).parent.resolve()

        if self.path.startswith("/api/"):
            return self._json(200, {"status":"api-ok","hint":"POST /api/verify, /api/install, /api/login"})

        if self.path == "/favicon.ico":
            self.send_response(204); self.end_headers(); return

        # Serve catalogs under /catalogs
        fs_path = (root / self.path.lstrip("/")).resolve()
        catalogs_root = (root / "catalogs").resolve()
        if str(fs_path).startswith(str(catalogs_root)) and fs_path.exists():
            try:
                data = fs_path.read_bytes()
                self.send_response(200)
                self.send_header("Content-Type", "application/json" if fs_path.suffix == ".json" else "application/octet-stream")
                self.end_headers(); self.wfile.write(data); return
            except Exception:
                pass

        # Route /
        if self.path in ("/", "/index.html"):
            # Choisir quoi rendre: token prompt si pas de licence, sinon install/login selon phase
            lic_ok = is_license_cached_ok(root)
            index_path = root / "public" / "index.html"
            if not index_path.exists() or not lic_ok:
                # Si pas de licence, on rend l'écran de saisie du token
                # On tente de pré-remplir via ?token=... si présent
                # (le JS se chargera d'envoyer /api/verify)
                # Important: on ne retourne pas ici; on laisse render_token_prompt écrire l'index
                render_token_prompt(root)
            # Sinon on laisse index.html tel qu'il est (install ou login ou accueil déjà écrit)
            self.send_response(200); self.send_header("Content-Type", "text/html; charset=utf-8"); self.end_headers()
            self.wfile.write((root / "public" / "index.html").read_bytes()); return

        self.send_response(404); self.end_headers()

    def do_POST(self):
        root = Path(__file__).parent.resolve()

        if self.path == "/api/verify":
            payload = self._read_json()
            tok = (payload.get("token") or "").strip()
            if not tok:
                return self._json(400, {"status":"error","message":"Token manquant"})
            vr = verify_token_online(root, tok)
            claims = vr.get("claims") or {}
            cache_entitlements(root, tok, claims)
            apply_entitlements_to_catalogs(root, claims)
            # Après vérif réussie (ou skip), afficher l'assistant d'installation
            render_install_page(root)
            status = "ok" if vr.get("status") in ("ok","skip") else "error"
            return self._json(200, {"status":status, "message":vr.get("message","")})

        if self.path == "/api/install":
            # Refuser si pas de licence
            if not is_license_cached_ok(root):
                return self._json(403, {"status":"error","message":"Licence requise. Veuillez valider un token."})
            payload = self._read_json()
            admin_ok = bool(payload.get("admin", {}).get("login") and payload.get("admin", {}).get("password"))
            dbs = payload.get("db", []) or []
            if not admin_ok:
                return self._json(400, {"status":"error","message":"Admin login & password requis"})

            # Normalisation silencieuse: si aucune base par defaut, forcer la première
            if dbs and not any(d.get("is_default") for d in dbs):
                dbs[0]["is_default"] = True
                payload["db"] = dbs

            write_json(root / "config/system_config.json", payload)
            write_json(root / "config/admin_account.json", payload.get("admin"))
            append_report(root, "install_completed", {"status": "completed"})
            append_log(root, "[install] configuration persisted (system_config.json)")

            render_home_login(root)
            return self._json(200, {"status":"completed","message":"Installation terminee. Redirection..."})

        if self.path == "/api/login":
            payload = self._read_json()
            try:
                with open(root / "config/admin_account.json","r",encoding="utf-8") as f:
                    admin = json.load(f)
            except FileNotFoundError:
                return self._json(400, {"status":"error","message":"Aucun compte admin configure"})
            ok = (payload.get("login")==admin.get("login")) and (payload.get("password")==admin.get("password"))
            if ok:
                render_home_app(root)
                return self._json(200, {"status":"ok", "redirect": "/"})
            return self._json(200, {"status":"error","message":"Identifiants invalides"})

        self._json(404, {"status":"error","message":"Not found"})

# -----------------------------
# Start + open
# -----------------------------
def start_and_open(root: Path, port: int, query_token: str = ""):
    httpd = HTTPServer(("", port), AppHandler)
    def run():
        print(f"[server] http on http://localhost:{port}")
        append_log(root, f"[server] http on {port}")
        httpd.erve_forever()

    # Typo fix: serve_forever
    def run_fixed():
        print(f"[server] http on http://localhost:{port}")
        append_log(root, f"[server] http on {port}")
        httpd.serve_forever()

    Thread(target=run_fixed, daemon=True).start()

    time.sleep(0.6)
    url = f"http://localhost:{port}/"
    if query_token:
        url += "?token=" + urllib.parse.quote(query_token)
    try:
        webbrowser.open_new_tab(url)
        append_log(root, f"[browser] auto-opened {url}")
    except Exception as e:
        append_log(root, f"[browser][error] {e}")

    while True: time.sleep(1)

# -----------------------------
# Main
# -----------------------------
def main():
    parser = argparse.ArgumentParser(add_help=False)
    parser.add_argument("--token", dest="token", default="")
    args, _ = parser.parse_known_args()

    root = Path(__file__).parent.resolve()
    ensure_dirs(root); append_log(root, "[bootstrap] start")
    install_min_catalogs(root); append_log(root, "[bootstrap] catalogs installed")

    # hooks
    register_hook_alias("hook_after", "hook_after_config_install", actions=["render_install_page"])
    append_log(root, "[bootstrap] hooks registered")

    # Décider de la première page: si on a déjà une licence OK, rendre install; sinon page token
    pre_token = load_token_from_sources(root, cli_token=args.token, query_token="")
    if pre_token:
        vr = verify_token_online(root, pre_token)
        claims = vr.get("claims") or {}
        cache_entitlements(root, pre_token, claims)
        apply_entitlements_to_catalogs(root, claims)
        # si ok/skip -> install, sinon prompt token (avec préremplissage via query)
        if vr.get("status") in ("ok","skip"):
            render_install_page(root)
        else:
            render_token_prompt(root, prefill_token=pre_token)
    else:
        render_token_prompt(root)

    start_and_open(root, PORT, query_token=pre_token)

if __name__ == "__main__":
    main()


Comment configurer le lien ensuite (campagne / email)
Tu as trois options simples, selon ton canal :


Lien direct avec token (si le bootstrap est déjà lancé chez l’utilisateur)
Dans ton mail/landing, mets un lien :
http://localhost:8081/?token=VOTRE_TOKEN
→ L’utilisateur clique, la page locale absorbe le token et te laisse installer.
(Utile pour relancer quelqu’un qui a déjà démarré l’outil.)


Lien “démarrage + token en paramètre”


Tu fournis d’abord le fichier bootstrap.py à télécharger.


Dans l’email, tu ajoutes : Votre token : VOTRE_TOKEN.


Option pratique : commande prête à copier-coller
bashCopier le codeINSTALL_TOKEN="VOTRE_TOKEN" python3 bootstrap.py

ou
bashCopier le codepython3 bootstrap.py --token VOTRE_TOKEN



→ Pas besoin d’ouvrir un lien localhost ; l’outil s’ouvrira tout seul avec le token pré-injecté.


Landing avec bouton “Copier token”


La landing génère le token via ton issuer, l’affiche et propose un bouton Copier.


L’utilisateur lance bootstrap.py, colle le token dans l’écran “Licence requise”, clique Valider.





Recommandation : pour les campagnes/email, privilégie l’option 2 (commande prête à l’emploi) — c’est la plus fiable et évite de dépendre d’un localhost déjà lancé.
L’option 1 est pratique en suivi (si la personne a déjà l’appli ouverte).
